-- Core control-plane schema: identities, API keys, workers, sessions, jobs, log lines.
-- Forward-only: append new migrations; do not edit this file after it has shipped.

CREATE TABLE identities (
    id TEXT PRIMARY KEY,
    agent_token_ciphertext BYTEA,
    git_token_ciphertext BYTEA,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Default BYOL identity; sessions omitting identity_id resolve to this row ([API_OVERVIEW §4a]).
INSERT INTO identities (id) VALUES ('default');

CREATE TABLE api_keys (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    key_hash TEXT NOT NULL,
    label TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    revoked_at TIMESTAMPTZ
);

CREATE UNIQUE INDEX api_keys_key_hash_uq ON api_keys (key_hash);

CREATE TABLE workers (
    id TEXT PRIMARY KEY,
    host TEXT,
    labels JSONB NOT NULL DEFAULT '{}'::jsonb,
    last_seen_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX workers_last_seen_idx ON workers (last_seen_at);

CREATE TABLE sessions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    identity_id TEXT NOT NULL DEFAULT 'default' REFERENCES identities (id),
    repo_url TEXT NOT NULL,
    git_ref TEXT NOT NULL DEFAULT 'main',
    workflow TEXT NOT NULL,
    status TEXT NOT NULL,
    params JSONB NOT NULL DEFAULT '{}'::jsonb,
    persona_id TEXT,
    retain_forever BOOLEAN NOT NULL DEFAULT false,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX sessions_status_idx ON sessions (status);

CREATE INDEX sessions_created_idx ON sessions (created_at DESC);

CREATE TABLE jobs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    session_id UUID NOT NULL REFERENCES sessions (id) ON DELETE CASCADE,
    status TEXT NOT NULL,
    worker_id TEXT REFERENCES workers (id) ON DELETE SET NULL,
    reclaim_count INTEGER NOT NULL DEFAULT 0,
    assigned_at TIMESTAMPTZ,
    completed_at TIMESTAMPTZ,
    error_message TEXT,
    pull_request_url TEXT,
    retain_forever BOOLEAN NOT NULL DEFAULT false,
    task_input JSONB,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX jobs_session_idx ON jobs (session_id);

CREATE INDEX jobs_pending_idx ON jobs (status)
WHERE
    status = 'pending';

CREATE INDEX jobs_assigned_worker_idx ON jobs (worker_id)
WHERE
    worker_id IS NOT NULL;

CREATE TABLE logs (
    id BIGSERIAL PRIMARY KEY,
    session_id UUID NOT NULL REFERENCES sessions (id) ON DELETE CASCADE,
    job_id UUID REFERENCES jobs (id) ON DELETE SET NULL,
    line_seq BIGINT NOT NULL,
    stream TEXT NOT NULL DEFAULT 'stdout',
    content TEXT NOT NULL,
    ingested_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (session_id, line_seq)
);

CREATE INDEX logs_job_idx ON logs (job_id);
